// ============================================================
// BYMB BRAND MACHINE — MASTER JSON BUILDER v3.0
// Compatible with: brand_machine_master.json schema
// Updated: 2026-03 — aligned agent keys, creative pack structure
// ============================================================

// ── HELPERS ─────────────────────────────────────────────────

const getNode = (name) => {
  try {
    const n = $(name);
    if (!n || !n.first()) return { _error: `NODE MISSING: "${name}" has no data` };
    return n.first().json;
  } catch (e) {
    return { _error: `NODE MISSING: "${name}" not found on canvas` };
  }
};

const getAllFromNode = (name) => {
  try { return $(name).all().map(i => i.json); }
  catch (e) { return []; }
};

const safeJson = (val) => {
  if (!val) return {};
  if (typeof val === 'string') { try { return JSON.parse(val); } catch { return {}; } }
  if (typeof val === 'object' && !Array.isArray(val)) return val;
  return {};
};

// Parse numeric score from prose: "10/10. The Navy..." → 10
// "High." → 9, "Medium" → 6, "Low" → 3
const parseScore = (str) => {
  if (str == null) return null;
  if (typeof str === 'number') return str;
  const s = String(str);
  const m = s.match(/^(\d+)\s*\/\s*10/);
  if (m) return parseInt(m[1], 10);
  const m2 = s.match(/(\d+)\s*\/\s*(\d+)/);
  if (m2) return Math.round(parseInt(m2[1], 10) / parseInt(m2[2], 10) * 10);
  const lower = s.toLowerCase();
  if (lower.startsWith('high'))   return 9;
  if (lower.startsWith('medium')) return 6;
  if (lower.startsWith('low'))    return 3;
  return null;
};

// Normalize language version keys — handles both "English Version" and "english_version"
const normalizeLang = (obj) => {
  if (!obj || typeof obj !== 'object') return { english_version: {}, arabic_version: {} };
  return {
    english_version:
      obj.english_version ||
      obj['English Version'] ||
      obj['english version'] ||
      obj.en ||
      obj || {},
    arabic_version:
      obj.arabic_version  ||
      obj['Arabic Version'] ||
      obj['arabic version'] ||
      obj.ar ||
      {},
  };
};

