const hasData= (obj) => obj && typeof obj === 'object' && !obj._error && Object.keys(obj).length > 0;
const safeArr= (val) => Array.isArray(val) ? val : [];

const formatDate = (iso) => {
  if (!iso) return new Date().toLocaleDateString('en-GB', { day:'numeric', month:'long', year:'numeric' });
  try { return new Date(iso).toLocaleDateString('en-GB', { day:'numeric', month:'long', year:'numeric' }); }
  catch { return iso; }
};

const md2html = (text) => {
  if (!text) return '';
  return String(text)
    .replace(/^### (.+)$/gm, '<h4 style="margin:2rem 0 1rem;font-size:1.2rem;color:var(--mn);">$1</h4>')
    .replace(/^## (.+)$/gm,  '<h3 style="color:var(--mn);border-bottom:2px solid var(--gd);margin:2.5rem 0 1.5rem;padding-bottom:0.5rem;font-size:1.5rem;">$1</h3>')
    .replace(/^# (.+)$/gm,   '<h2 style="font-size:1.8rem;margin:3rem 0 1.5rem;">$1</h2>')
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/^- (.+)$/gm, '<li>$1</li>')
    .replace(/(<li>.*<\/li>)/gs, match => `<ul style="padding-left:1.5rem;margin:1rem 0;">${match}</ul>`)
    .replace(/\n{2,}/g, '</p><p style="margin-bottom:1rem;">')
    .replace(/\n/g, '<br>');
};

