function buildStrategy() {
  let html = '';

  // UVP
  const uvp = a1.unique_value_proposition || '';
  if (uvp) html += `<div class="card col-full"><h3>Unique Value Proposition</h3><p class="quote">${esc(uvp)}</p></div>`;

  // Positioning statement
  const pos = a1.positioning_statement || {};
  if (hasData(pos)) {
    html += '<div class="grid-2">';
    for (const [k, val] of Object.entries(pos)) {
      if (!val) continue;
      html += `<div class="card"><h3>${esc(k.replace(/_/g,' '))}</h3><p>${esc(val)}</p></div>`;
    }
    html += '</div>';
  }

  // Archetype
  const arch = a1.brand_archetype || {};
  if (hasData(arch)) {
    const emojiMap = { sage:'🧙', creator:'🎨', hero:'⚔️', ruler:'👑', caregiver:'💛', explorer:'🧭', innocent:'🌸', jester:'🎭', lover:'💎', magician:'✨', outlaw:'🔥', everyman:'🤝' };
    const key = (arch.primary||'').toLowerCase().split(' ')[0];
    const emoji = emojiMap[key] || '🎯';
    html += `<div class="card"><h3>Brand Archetype</h3>
      <div style="display:flex;align-items:flex-start;gap:1.5rem;">
        <div style="font-size:3rem;line-height:1;">${emoji}</div>
        <div>
          <p style="font-size:1.8rem;font-weight:700;color:var(--gd);font-family:var(--fh);margin-bottom:0.5rem;">${esc(arch.primary||'')}</p>
          <p style="color:var(--mg);margin-bottom:0.75rem;">Secondary: ${esc(arch.secondary||'')}</p>
          <p>${esc(arch.justification||'')}</p>
        </div>
      </div></div>`;
  }

  // Customer Transformation
  const ct = a1.customer_transformation || {};
  if (ct.before || ct.after) {
    html += `<div class="card col-full"><h3>Customer Transformation</h3>
      <div style="display:grid;grid-template-columns:1fr auto 1fr auto 1fr;align-items:center;gap:1rem;margin-top:1rem;">
        <div style="padding:1.5rem;background:var(--sg);border-radius:var(--rmd);">
          <p style="font-size:0.75rem;font-weight:700;color:var(--mg);letter-spacing:0.15em;text-transform:uppercase;margin-bottom:0.5rem;">Before</p>
          <p>${esc(ct.before||'')}</p>
        </div>
        <div style="font-size:1.5rem;color:var(--gd);">→</div>
        <div style="padding:1.5rem;background:rgba(201,168,76,0.1);border:1px solid var(--gd);border-radius:var(--rmd);text-align:center;">
          <p style="font-size:0.75rem;font-weight:700;color:var(--gd);letter-spacing:0.15em;text-transform:uppercase;margin-bottom:0.5rem;">Emotional Shift</p>
          <p style="font-style:italic;color:var(--gd);">${esc(ct.emotional_shift||'')}</p>
        </div>
        <div style="font-size:1.5rem;color:var(--gd);">→</div>
        <div style="padding:1.5rem;background:var(--sg);border-radius:var(--rmd);">
          <p style="font-size:0.75rem;font-weight:700;color:var(--mn);letter-spacing:0.15em;text-transform:uppercase;margin-bottom:0.5rem;">After</p>
          <p>${esc(ct.after||'')}</p>
        </div>
      </div></div>`;
  }

  // Personality & Emotional Drivers
  const traits  = safeArr(a1.brand_personality_traits);
  const drivers = safeArr(a1.emotional_drivers);
  if (traits.length || drivers.length) {
    html += '<div class="grid-2">';
    if (traits.length)  html += `<div class="card"><h3>Brand Personality</h3><ul class="tag-list">${traits.map(t => `<li>${esc(typeof t === 'object' ? t.trait||JSON.stringify(t) : t)}</li>`).join('')}</ul></div>`;
    if (drivers.length) html += `<div class="card"><h3>Emotional Drivers</h3><ul class="tag-list tag-list--muted">${drivers.map(d => `<li>${esc(typeof d === 'object' ? d.driver||JSON.stringify(d) : d)}</li>`).join('')}</ul></div>`;
    html += '</div>';
  }

  // Messaging Pillars
  const pillars = safeArr(a1.messaging_pillars);
  if (pillars.length) {
    html += `<div class="card"><h3>Messaging Pillars</h3><div class="grid-3" style="margin-top:1rem;">
      ${pillars.map((p, i) => {
        if (typeof p === 'object') return `<div class="pillar"><span class="pillar-num">0${i+1}</span><strong>${esc(p.title||p.name||'')}</strong><p>${esc(p.description||p.detail||'')}</p></div>`;
        return `<div class="pillar"><span class="pillar-num">0${i+1}</span><p>${esc(p)}</p></div>`;
      }).join('')}
    </div></div>`;
  }

  // Tone of Voice
  const tov = a1.tone_of_voice || {};
  if (hasData(tov)) {
    html += `<div class="card"><h3>Tone of Voice</h3>
      <p style="font-style:italic;margin-bottom:1.5rem;">"${esc(tov.description||'')}"</p>
      <div class="grid-2">
        <div>
          <p style="font-weight:700;color:var(--suc);margin-bottom:0.75rem;">✓ Do's</p>
          <ul style="list-style:none;padding:0;">${safeArr(tov.dos).map(d => `<li style="padding:0.4rem 0;border-bottom:1px solid var(--border);color:var(--suc);">✓ ${esc(d)}</li>`).join('')}</ul>
        </div>
        <div>
          <p style="font-weight:700;color:var(--dng);margin-bottom:0.75rem;">✕ Don'ts</p>
          <ul style="list-style:none;padding:0;">${safeArr(tov.donts).map(d => `<li style="padding:0.4rem 0;border-bottom:1px solid var(--border);color:var(--dng);">✕ ${esc(d)}</li>`).join('')}</ul>
        </div>
      </div></div>`;
  }

  // Strategic Risks
  const risks = safeArr(a1.strategic_risks);
  if (risks.length) {
    html += `<div class="card"><h3>Strategic Risks &amp; Mitigations</h3>
      ${risks.map(r => `<div style="padding:1rem;margin-bottom:0.75rem;background:rgba(196,75,75,0.05);border-left:3px solid var(--dng);border-radius:0 var(--rmd) var(--rmd) 0;">
        <p style="font-weight:700;color:var(--dng);margin-bottom:0.4rem;">⚠ ${esc(r.risk||'')}</p>
        <p style="font-size:0.95rem;"><strong>Mitigation:</strong> ${esc(r.mitigation||'')}</p>
      </div>`).join('')}</div>`;
  }

  // Arabic version
  if (hasData(a1_ar)) {
    html += `<div dir="rtl" lang="ar" class="arabic-section"><h3>النسخة العربية — الاستراتيجية</h3>
      ${a1_ar.unique_value_proposition ? `<div class="card"><h3>القيمة المقترحة الفريدة</h3><p class="quote">${esc(a1_ar.unique_value_proposition)}</p></div>` : ''}
    </div>`;
  }

  return html || '<div class="card"><p class="empty">Strategy data will appear here once Agent 1 completes.</p></div>';
}

