        <p style="font-size:1.2rem;font-weight:700;color:var(--mn);margin-bottom:0.75rem;">${esc(a2.recommended_market_entry_strategy?.strategy_type||'')}</p>
        <p>${esc(a2.recommended_market_entry_strategy?.justification||'')}</p>
      </div>
    </div>`;
  }

  // Competitor analysis
  const ca = a2.competitor_pattern_analysis || {};
  if (hasData(ca)) {
    html += '<div class="grid-2">';
    const caItems = [
      ['Common Positioning Themes', ca.common_positioning_themes],
      ['Overused Messaging Angles', ca.overused_messaging_angles],
      ['Visual Identity Trends',    ca.visual_identity_trends],
      ['Pricing Patterns',          ca.pricing_patterns],
    ];
    for (const [label, arr] of caItems) {
      const items = safeArr(arr);
      if (!items.length) continue;
      html += `<div class="card"><h3>${label}</h3><ul class="pillar-list">${items.map(i => `<li>${esc(typeof i === 'object' ? JSON.stringify(i) : i)}</li>`).join('')}</ul></div>`;
    }
    html += '</div>';
  }

  // White space
  const ws = safeArr(a2.white_space_opportunities);
  if (ws.length) {
    html += `<div class="card"><h3>White Space Opportunities</h3><ul class="pillar-list">${ws.map(w => `<li>${esc(typeof w === 'object' ? w.opportunity||JSON.stringify(w) : w)}</li>`).join('')}</ul></div>`;
  }

  // Differentiation + long term
  if (a2.strategic_differentiation_angle) {
    html += `<div class="card"><h3>Strategic Differentiation Angle</h3><p class="quote">${esc(a2.strategic_differentiation_angle)}</p></div>`;
  }
  if (a2.long_term_strategic_advantage) {
    html += `<div class="card"><h3>Long-term Strategic Advantage</h3><p>${esc(a2.long_term_strategic_advantage)}</p></div>`;
  }

  return html || '<div class="card"><p class="empty">Market intelligence will appear here once Agent 2 completes.</p></div>';
}

function buildVisualIdentity() {
  let html = '';

  const vpc = a3.visual_positioning_concept || {};
  if (vpc.creative_direction_statement) {
    html += `<div class="card col-full"><h3>Creative Direction</h3><p class="quote">${esc(vpc.creative_direction_statement)}</p></div>`;
  }
  if (vpc.desired_feel || vpc.visual_avoidance) {
    html += '<div class="grid-2">';
    if (vpc.desired_feel)    html += `<div class="card"><h3>Desired Feel</h3><p>${esc(vpc.desired_feel)}</p></div>`;
    if (vpc.visual_avoidance) html += `<div class="card"><h3>Visual Avoidance</h3><p>${esc(vpc.visual_avoidance)}</p></div>`;
    html += '</div>';
  }

  // Color strategy
  const cs = a3.color_strategy || {};
  if (hasData(cs)) {
    html += '<div class="card"><h3>Color Strategy</h3>';
    for (const [k, val] of Object.entries(cs)) {
      if (typeof val !== 'string') continue;
      html += `<p><strong>${esc(k.replace(/_/g,' '))}:</strong> ${esc(val)}</p>`;
    }
    html += '</div>';
  }

  // Typography direction
  const td = a3.typography_direction || {};
  if (hasData(td)) {
    html += '<div class="card"><h3>Typography Direction</h3><div class="grid-2" style="margin-top:0.5rem;">';
    for (const [k, val] of Object.entries(td)) {
      if (!val) continue;
      html += `<div><strong style="font-size:0.8rem;text-transform:uppercase;letter-spacing:0.1em;">${esc(k.replace(/_/g,' '))}</strong><p style="margin-top:0.25rem;">${esc(val)}</p></div>`;
    }
    html += '</div></div>';
  }

  // Imagery direction
  const id_ = a3.imagery_direction || {};
  if (hasData(id_)) {
    html += '<div class="card"><h3>Imagery Direction</h3>';
    for (const [k, val] of Object.entries(id_)) {
      if (!val) continue;
      html += `<p><strong>${esc(k.replace(/_/g,' '))}:</strong> ${esc(val)}</p>`;
    }
    html += '</div>';
  }

  // Visual consistency rules
  const rules = a3.visual_consistency_rules || {};
  if (hasData(rules)) {
    html += '<div class="card"><h3>Visual Consistency Rules</h3>';
    const nn = safeArr(rules.non_negotiables);
    if (nn.length) {
      html += '<ul style="list-style:none;padding:0;">';
      nn.forEach(r => html += `<li style="padding:0.75rem 0;border-bottom:1px solid var(--border);">✓ ${esc(r)}</li>`);
      html += '</ul>';
    }
    const misuse = safeArr(rules.misuse_to_avoid);
    if (misuse.length) {
      html += '<h4 style="margin-top:1.5rem;color:var(--dng);">Misuses to Avoid</h4><ul style="list-style:none;padding:0;">';
      misuse.forEach(r => html += `<li style="padding:0.5rem 0;color:var(--dng);">✕ ${esc(r)}</li>`);
      html += '</ul>';
    }
    html += '</div>';
  }

  return html || '<div class="card"><p class="empty">Visual identity will appear here once Agent 3 completes.</p></div>';
}

function buildPalette() {
  // Primary source: Agent4.english_version.brand_guidelines.color_guidelines
  // + Pantone from Agent3.creative_pack_agents.pantone_approximator.output
  const allColors = [...primPalette, ...secPalette];
  const pantoneRoles = ['primary', 'secondary', 'accent', 'neutral'];
  let swatches = '';

  allColors.forEach((c, i) => {
    if (!c?.hex) return;
    const pms = cpPMS[pantoneRoles[i]] || {};
    const confColor = { exact: 'var(--suc)', close: 'var(--wrn)', approximate: 'var(--dng)' }[pms.match_confidence] || 'var(--mg)';
    const isLight = c.hex.toUpperCase() === '#FFFFFF' || c.hex.toLowerCase().startsWith('#f');
    swatches += `
      <div class="swatch-card">
        <div class="swatch-block" style="background:${c.hex};${isLight ? 'border:1px solid rgba(26,39,68,0.1);' : ''}"></div>
        <div class="swatch-meta">
          <span class="swatch-role">${esc(i < primPalette.length ? 'primary' : 'secondary')}</span>
          <span class="swatch-name">${esc(c.name||'')}</span>
          <code class="swatch-hex">${esc(c.hex)}</code>
          <p style="font-size:0.8rem;color:var(--mg);margin-top:0.3rem;">${esc(c.usage||'')}</p>
          ${pms.pantone_pms ? `<p style="font-size:0.75rem;margin-top:0.4rem;">
            <span style="font-weight:700;color:var(--gd);">${esc(pms.pantone_pms)}</span>
            <span style="color:${confColor};margin-left:0.5rem;">${esc(pms.match_confidence||'')}</span>
          </p>` : ''}
        </div>
      </div>`;
  });

  return swatches || '<p class="empty">Color palette will be generated once agents complete.</p>';
}

