function buildLogos() {
  // Agent3.creative_pack_agents.logo_generator.output[] — array of variations
  let html = '';
  const logos = Array.isArray(cpLogo) ? cpLogo : [];

  if (logos.length) {
    html = logos.map((logo, i) => {
      if (!logo) return '';
      const svg = logo.svg || '';
      const id  = logo.id || `variation-${i+1}`;
      const isDark = id.includes('reversed') || id.includes('dark');
      const bg    = isDark ? 'var(--mn)' : 'var(--wh)';
      const border= isDark ? '' : 'border:1px solid var(--border);';
      const svgContent = svg.includes('<svg') ? svg : `<div style="padding:3rem;text-align:center;color:var(--mg);font-style:italic;">${esc(id)} — SVG pending</div>`;
      return `<div class="card" style="text-align:center;">
        <h3>${esc(id.replace(/_/g,' '))}</h3>
        <div style="background:${bg};padding:3rem;border-radius:var(--rmd);margin:1rem 0;${border}overflow:auto;">${svgContent}</div>
        ${logo.elements_used?.length ? `<p style="font-size:0.75rem;color:var(--mg);">Elements: ${esc(logo.elements_used.join(', '))}</p>` : ''}
        ${logo.generation_notes ? `<p style="font-size:0.8rem;color:var(--mg);margin-top:0.5rem;font-style:italic;">${esc(logo.generation_notes)}</p>` : ''}
      </div>`;
    }).join('');
  }

  return html || `<div class="card" style="text-align:center;"><h3>Logo</h3>
    <div style="background:var(--mn);padding:4rem;border-radius:var(--rmd);">
      <svg viewBox="0 0 200 60" style="max-width:300px;"><text x="50%" y="50%" dominant-baseline="middle" text-anchor="middle" fill="white" font-family="${esc(fontHead)},sans-serif" font-size="32" font-weight="700">${esc(brandName)}</text></svg>
    </div>
    <p class="empty" style="margin-top:1rem;">Logo SVGs will be generated by the Creative Pack.</p>
  </div>`;
}

