function buildAudit() {
  // Agent4.english_version.scores + alignment_check + brand_guidelines
  let html = '';

  // Score bars
  const scoreItems = [
    ['Positioning Clarity',      a4scores.positioning_clarity],
    ['Differentiation Strength', a4scores.differentiation_strength],
    ['Execution Complexity',     a4scores.execution_complexity],
    ['Risk Level',               a4scores.risk_level],
  ];
  const scoreBars = scoreItems.filter(([,v]) => v !== '' && v != null);
  if (scoreBars.length) {
    html += '<div class="card"><h3>Audit Scores</h3>';
    for (const [label, val] of scoreBars) {
      const numVal = typeof val === 'number' ? val : null;
      const pct    = numVal !== null ? Math.min(numVal * 10, 100) : 50;
      html += `<div class="score-row"><span class="score-label">${esc(label)}</span><div class="score-track"><div class="score-fill" style="width:${pct}%"></div></div><span class="score-val">${esc(String(val))}</span></div>`;
    }
    html += '</div>';
  }

  // Alignment check prose
  if (hasData(a4align)) {
    html += '<div class="card"><h3>Alignment Check</h3>';
    for (const [k, val] of Object.entries(a4align)) {
      if (!val) continue;
      html += `<p style="margin-bottom:1rem;"><strong>${esc(k.replace(/_/g,' '))}:</strong> ${esc(val)}</p>`;
    }
    html += '</div>';
  }

  // Brand guidelines overview + logo/color/type
  if (a4gl.overview?.mission_statement) {
    html += `<div class="card"><h3>Mission Statement</h3><p class="quote">${esc(a4gl.overview.mission_statement)}</p></div>`;
  }

  // Logo guidelines
  const logoGL = a4gl.logo_guidelines || {};
  if (hasData(logoGL)) {
    html += `<div class="card"><h3>Logo Usage Rules</h3>
      ${logoGL.description ? `<p style="margin-bottom:1rem;">${esc(logoGL.description)}</p>` : ''}
      <div class="grid-2" style="margin-bottom:1rem;">
        ${logoGL.minimum_size ? `<div><strong>Min Size:</strong> ${esc(logoGL.minimum_size)}</div>` : ''}
        ${logoGL.clear_space  ? `<div><strong>Clear Space:</strong> ${esc(logoGL.clear_space)}</div>`  : ''}
      </div>
      ${safeArr(logoGL.incorrect_usage).length ? `<p style="font-weight:700;color:var(--dng);margin-bottom:0.5rem;">Incorrect Usage</p><ul style="list-style:none;padding:0;">${safeArr(logoGL.incorrect_usage).map(u => `<li style="color:var(--dng);padding:0.3rem 0;">✕ ${esc(u)}</li>`).join('')}</ul>` : ''}
    </div>`;
  }

  // Imagery guidelines
  const imgGL = a4gl.imagery_guidelines || {};
  if (hasData(imgGL)) {
    html += `<div class="card"><h3>Imagery Guidelines</h3>
      ${imgGL.style ? `<p style="margin-bottom:1rem;">${esc(imgGL.style)}</p>` : ''}
      <div class="grid-2">
        ${safeArr(imgGL.dos).length  ? `<div><p style="font-weight:700;color:var(--suc);margin-bottom:0.5rem;">✓ Do's</p><ul style="list-style:none;padding:0;">${safeArr(imgGL.dos).map(d => `<li style="color:var(--suc);padding:0.3rem 0;">✓ ${esc(d)}</li>`).join('')}</ul></div>` : ''}
        ${safeArr(imgGL.donts).length? `<div><p style="font-weight:700;color:var(--dng);margin-bottom:0.5rem;">✕ Don'ts</p><ul style="list-style:none;padding:0;">${safeArr(imgGL.donts).map(d => `<li style="color:var(--dng);padding:0.3rem 0;">✕ ${esc(d)}</li>`).join('')}</ul></div>` : ''}
      </div>
    </div>`;
  }

  return html || '<div class="card"><p class="empty">Audit results will appear here once Agent 4 completes.</p></div>';
}

function buildReport() {
