  } else if (a5en.full_report_markdown) {
    html += `<div class="card markdown-body"><p>${md2html(v(a5en.full_report_markdown))}</p></div>`;
  }

  // Final conclusion
  if (a5en.final_conclusion) {
    html += `<div class="card" style="border-left:4px solid var(--gd);background:rgba(201,168,76,0.05);">
      <h3>Final Conclusion</h3>
      <p class="quote">${esc(a5en.final_conclusion)}</p>
    </div>`;
  }

