const englishVersion = $input.first().json.output.english_version;
const brandName = $('On form submission1').first().json.brand_name;

if (!englishVersion) {
  throw new Error('Missing: output.english_version from Agent 3');
}
if (!brandName) {
  throw new Error('Missing: brand_name from form submission');
}

function toMarkdown(value, depth = 0) {
  if (Array.isArray(value)) {
    return value.map((item, index) => {
      if (typeof item === 'object' && item !== null) {
        const indent = '  '.repeat(depth);
        const itemLines = Object.entries(item).map(([k, v]) => {
          if (typeof v === 'object' && v !== null) {
            return `${indent}  - **${k}**:\n${toMarkdown(v, depth + 2)}`;
          }
          return `${indent}  - **${k}**: ${v}`;
        }).join('\n');
        return `${indent}- Item ${index + 1}:\n${itemLines}`;
      }
      return `${'  '.repeat(depth)}- ${item}`;
    }).join('\n\n');
  }

  if (typeof value !== 'object' || value === null) {
    return String(value);
  }

  if (depth >= 5) {
    return JSON.stringify(value);
  }

  return Object.entries(value)
    .map(([k, v]) => {
      const indent = '  '.repeat(depth);
      const heading = '#'.repeat(Math.min(depth + 2, 6));
      if (typeof v === 'object' && v !== null && !Array.isArray(v) && depth < 4) {
        return `${indent}${heading} ${k}\n\n${toMarkdown(v, depth + 1)}`;
      }
      if (Array.isArray(v)) {
        return `${indent}- **${k}**:\n${toMarkdown(v, depth + 1)}`;
      }
      const val = (typeof v === 'object' && v !== null) ? JSON.stringify(v) : v;
      return `${indent}- **${k}**: ${val}`;
    })
    .join('\n\n');
}

const md = Object.entries(englishVersion)
  .map(([section, fields]) => {
    return `## ${section}\n\n${toMarkdown(fields, 1)}`;
  })
  .join('\n\n---\n\n');

return $input.all().map(item => ({
  ...item,
  json: {
    ...item.json,
    brand_name: brandName,
    agent3_brief_md: md,
  }
}));
